(function () {
const wrapper = document.querySelector('.carousel-slides');
const dots = document.querySelector('.carousel-dots');
const prev = document.querySelector('.carousel-prev');
const next = document.querySelector('.carousel-next');
if (!wrapper) return;
const slides = wrapper.querySelectorAll('.carousel-slide');
let current = 0, timer;
slides.forEach((_, i) => {
const d = document.createElement('button');
d.className = 'dot' + (i === 0 ? ' active' : '');
d.setAttribute('aria-label', 'Go to slide ' + (i + 1));
d.addEventListener('click', () => goTo(i));
if (dots) dots.appendChild(d);
});
function goTo(n) {
const allDots = dots ? dots.querySelectorAll('.dot') : [];
if (allDots[current]) allDots[current].classList.remove('active');
current = (n + slides.length) % slides.length;
wrapper.style.transform = `translateX(-${current * 100}%)`;
if (allDots[current]) allDots[current].classList.add('active');
clearInterval(timer);
timer = setInterval(() => goTo(current + 1), 5800);
}
if (prev) prev.addEventListener('click', () => goTo(current - 1));
if (next) next.addEventListener('click', () => goTo(current + 1));
let tx = 0;
wrapper.addEventListener('touchstart', e => { tx = e.touches[0].clientX; }, { passive: true });
wrapper.addEventListener('touchend', e => {
const diff = tx - e.changedTouches[0].clientX;
if (Math.abs(diff) > 50) diff > 0 ? goTo(current + 1) : goTo(current - 1);
});
document.addEventListener('keydown', e => {
if (e.key === 'ArrowRight') goTo(current + 1);
if (e.key === 'ArrowLeft') goTo(current - 1);
});
timer = setInterval(() => goTo(current + 1), 5800);
})();
(function () {
const toggle = document.querySelector('.nav-toggle');
const mobileNav = document.querySelector('.mobile-nav');
if (!toggle || !mobileNav) return;
toggle.addEventListener('click', () => {
const open = mobileNav.classList.toggle('open');
toggle.classList.toggle('open', open);
document.body.style.overflow = open ? 'hidden' : '';
});
mobileNav.querySelectorAll('.mobile-nav-link[data-sub]').forEach(link => {
link.addEventListener('click', e => {
e.preventDefault();
const item = link.closest('.mobile-nav-item');
item.classList.toggle('sub-open');
});
});
})();
(function () {
document.querySelectorAll('.faq-q').forEach(q => {
q.addEventListener('click', () => {
const item = q.closest('.faq-item');
const answer = item.querySelector('.faq-a');
const isOpen = item.classList.contains('open');
document.querySelectorAll('.faq-item').forEach(i => {
i.classList.remove('open');
const a = i.querySelector('.faq-a');
if (a) a.style.maxHeight = '0';
});
if (!isOpen) {
item.classList.add('open');
answer.style.maxHeight = answer.scrollHeight + 'px';
}
});
});
})();
(function () {
const tabs = document.querySelectorAll('.plan-tab');
tabs.forEach(tab => {
tab.addEventListener('click', () => {
tabs.forEach(t => t.classList.remove('active'));
tab.classList.add('active');
const billing = tab.dataset.billing;
document.querySelectorAll('.price-monthly').forEach(el => {
el.style.display = billing === 'monthly' ? '' : 'none';
});
document.querySelectorAll('.price-annual').forEach(el => {
el.style.display = billing === 'annual' ? '' : 'none';
});
});
});
})();
(function () {
const bar = document.querySelector('.sticky-offer');
const closeBtn = document.querySelector('.sticky-close');
if (!bar) return;
let dismissed = false;
window.addEventListener('scroll', () => {
if (dismissed) return;
bar.classList.toggle('show', window.scrollY > 700);
});
if (closeBtn) closeBtn.addEventListener('click', () => {
dismissed = true;
bar.classList.remove('show');
});
})();
(function () {
const btn = document.querySelector('.announcement-close');
const bar = document.querySelector('.announcement-bar');
if (btn && bar) btn.addEventListener('click', () => bar.remove());
})();
(function () {
const form = document.querySelector('.domain-form');
const input = document.querySelector('.domain-input');
const results = document.querySelector('.domain-results');
if (!form) return;
function siteBase() {
const s = document.querySelector('script[src*="main"]');
if (s && s.src) return s.src.replace(/\/js\/main[^\/]*\.js.*$/i, '');
return '';
}
const API = siteBase() + '/api/domain-check.php';
form.addEventListener('submit', e => {
e.preventDefault();
if (!input || !results) return;
const raw = input.value.trim();
if (!raw) return;
const submitBtn = form.querySelector('button[type="submit"]');
if (submitBtn) { submitBtn.disabled = true; submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Searching…'; }
results.innerHTML = '<div style="text-align:center;padding:28px 0;color:var(--text-muted);font-size:0.9375rem"><i class="fas fa-spinner fa-spin"></i> Checking availability…</div>';
const done = () => {
if (submitBtn) { submitBtn.disabled = false; submitBtn.innerHTML = 'Search <i class="fas fa-search"></i>'; }
};
fetch(API + '?q=' + encodeURIComponent(raw))
.then(r => r.json())
.then(data => {
done();
if (!data.ok) {
results.innerHTML = `<div style="text-align:center;padding:28px 0;color:var(--text-muted);font-size:0.9375rem"><i class="fas fa-circle-info"></i> ${data.error || 'Search is unavailable right now.'}</div>`;
return;
}
const rows = data.results.map(r => {
const avail = r.available; // true | false | null
const cls = avail === true ? 'result-available' : (avail === false ? 'result-taken' : '');
const icon = avail === true ? 'fa-check-circle' : (avail === false ? 'fa-times-circle' : 'fa-circle-question');
const statusText = avail === true ? 'Available' : (avail === false ? 'Taken' : 'Check with us');
const price = `${r.currency} ${Number(r.price).toFixed(2)}/yr`;
const cartUrl = (window.WHMCS && avail === true) ? window.WHMCS.domainUrl(r.domain) : '#';
const action = avail === true
? `<a href="${cartUrl}" class="btn btn-green btn-sm">Add to Cart</a>`
: (avail === false
? `<span class="btn btn-outline-navy btn-sm" style="opacity:.45;cursor:default;">Unavailable</span>`
: `<a href="contact.html" class="btn btn-outline-navy btn-sm">Ask us</a>`);
return `
<div class="domain-result-row ${cls}">
<span class="result-name">${r.domain}</span>
<span class="result-status"><i class="fas ${icon}"></i> ${statusText}</span>
<span class="result-price">${avail === false ? '' : price}</span>
${action}
</div>`;
}).join('');
results.innerHTML = `<div class="domain-results-inner">${rows}</div>`;
})
.catch(() => {
done();
results.innerHTML = '<div style="text-align:center;padding:28px 0;color:var(--text-muted);font-size:0.9375rem"><i class="fas fa-triangle-exclamation"></i> Search is temporarily unavailable. Please try again shortly.</div>';
});
});
document.querySelectorAll('.tld-pill').forEach(pill => {
pill.addEventListener('click', () => {
if (input) {
const tld = pill.dataset.tld;
if (!input.value) input.value = 'yourdomain';
input.value = input.value.replace(/\.[a-z.]+$/, '') + tld;
input.focus();
}
});
});
})();
(function () {
const io = new IntersectionObserver(entries => {
entries.forEach(e => {
if (e.isIntersecting) { e.target.classList.add('visible'); io.unobserve(e.target); }
});
}, { threshold: 0.08 });
document.querySelectorAll('.animate-in').forEach(el => io.observe(el));
})();
(function () {
const io = new IntersectionObserver(entries => {
entries.forEach(e => {
if (!e.isIntersecting) return;
const el = e.target;
const end = parseFloat(el.dataset.count);
const suffix = el.dataset.suffix || '';
const dec = el.dataset.decimal || 0;
let current = 0;
const step = end / 55;
const run = () => {
current = Math.min(current + step, end);
el.textContent = current.toFixed(dec) + suffix;
if (current < end) requestAnimationFrame(run);
else el.textContent = end.toFixed(dec) + suffix;
};
requestAnimationFrame(run);
io.unobserve(el);
});
}, { threshold: 0.5 });
document.querySelectorAll('[data-count]').forEach(el => io.observe(el));
})();
(function () {
const bar = document.createElement('div');
bar.className = 'reading-progress';
document.body.prepend(bar);
window.addEventListener('scroll', () => {
const h = document.documentElement.scrollHeight - window.innerHeight;
bar.style.width = h > 0 ? (window.scrollY / h * 100) + '%' : '0%';
}, { passive: true });
})();
(function () {
const btn = document.createElement('button');
btn.type = 'button';
btn.className = 'back-to-top';
btn.setAttribute('aria-label', 'Back to top');
btn.innerHTML = '<i class="fas fa-chevron-up"></i>';
document.body.appendChild(btn);
btn.addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));
function reposition() {
const stickyOn = document.querySelector('.sticky-offer')?.classList.contains('show');
const base = stickyOn ? 90 : 24;
const chat = document.querySelector('.chat-widget');
if (chat) chat.style.bottom = base + 'px';
btn.style.bottom = (base + 64) + 'px';
btn.classList.toggle('visible', window.scrollY > 600);
}
window.addEventListener('scroll', reposition, { passive: true });
reposition();
})();
(function () {
function siteBase() {
const s = document.querySelector('script[src*="main"]');
if (s && s.src) return s.src.replace(/\/js\/main[^\/]*\.js.*$/i, '');
return '';
}
const API = siteBase() + '/api/chat.php';
const store = {
get conv() { return localStorage.getItem('oh_chat_conv'); },
get token() { return localStorage.getItem('oh_chat_token'); },
save(c, t) { localStorage.setItem('oh_chat_conv', c); localStorage.setItem('oh_chat_token', t); },
};
const widget = document.createElement('div');
widget.className = 'chat-widget';
widget.style.bottom = '24px';
widget.innerHTML =
'<div class="chat-panel" id="chatPanel">' +
'<div class="chat-ph">' +
'<div class="chat-ph-av"><i class="fas fa-headset"></i></div>' +
'<div class="chat-ph-info">' +
'<div class="chat-ph-name">OrbitHost Support</div>' +
'<div class="chat-ph-status"><span class="chat-status-dot"></span> We reply as soon as we can</div>' +
'</div>' +
'<button type="button" class="chat-ph-x" aria-label="Close chat"><i class="fas fa-times"></i></button>' +
'</div>' +
'<div class="chat-pb" id="chatBody">' +
'<div class="chat-bubble">&#128075; Hi there! How can we help you today?</div>' +
'<div class="chat-lead" id="chatLead">' +
'<input type="text" class="chat-input" id="chatName" placeholder="Your name (optional)" style="margin-bottom:6px" />' +
'<input type="email" class="chat-input" id="chatEmail" placeholder="Email for replies (optional)" />' +
'</div>' +
'</div>' +
'<div class="chat-pf">' +
'<input type="text" class="chat-input" id="chatText" placeholder="Type a message…" maxlength="2000" />' +
'<button type="button" class="chat-send" id="chatSend" aria-label="Send message"><i class="fas fa-paper-plane"></i></button>' +
'</div>' +
'</div>' +
'<button type="button" class="chat-btn" id="chatToggle" aria-label="Open live chat">' +
'<i class="fas fa-comments"></i>' +
'<span class="chat-badge" style="display:none">1</span>' +
'</button>';
document.body.appendChild(widget);
const panel = widget.querySelector('#chatPanel');
const toggle = widget.querySelector('#chatToggle');
const badge = widget.querySelector('.chat-badge');
const body = widget.querySelector('#chatBody');
const lead = widget.querySelector('#chatLead');
const text = widget.querySelector('#chatText');
const send = widget.querySelector('#chatSend');
let lastId = 0, timer = null;
function bubble(msg, mine, who) {
const div = document.createElement('div');
div.className = 'chat-bubble' + (mine ? ' chat-bubble--me' : '');
div.textContent = msg;
if (!mine && who) div.setAttribute('data-who', who);
body.appendChild(div);
body.scrollTop = body.scrollHeight;
}
function poll() {
if (!store.conv) return;
fetch(API + '?action=poll&conversation=' + encodeURIComponent(store.conv) +
'&token=' + encodeURIComponent(store.token) + '&after=' + lastId)
.then(r => r.json())
.then(d => {
if (!d.ok) return;
d.messages.forEach(m => {
lastId = Math.max(lastId, Number(m.id));
if (m.sender === 'admin') {
bubble(m.message, false, m.sender_name || 'Support');
if (!panel.classList.contains('open') && badge) badge.style.display = 'flex';
} else if (!m._local) {
if (!body.querySelector('[data-mid="' + m.id + '"]')) {
const el = document.createElement('div');
el.className = 'chat-bubble chat-bubble--me';
el.textContent = m.message;
el.setAttribute('data-mid', m.id);
body.appendChild(el);
body.scrollTop = body.scrollHeight;
}
}
});
})
.catch(() => {});
}
function startPolling() {
if (timer) return;
poll();
timer = setInterval(poll, 4000);
}
function doSend() {
const msg = text.value.trim();
if (!msg) return;
text.value = '';
bubble(msg, true);
if (lead) lead.style.display = 'none';
const form = new FormData();
if (!store.conv) {
form.append('action', 'start');
form.append('message', msg);
form.append('name', (widget.querySelector('#chatName') || {}).value || '');
form.append('email', (widget.querySelector('#chatEmail') || {}).value || '');
} else {
form.append('action', 'send');
form.append('conversation', store.conv);
form.append('token', store.token);
form.append('message', msg);
}
fetch(API, { method: 'POST', body: form })
.then(r => r.json())
.then(d => {
if (d.ok && d.conversation) { store.save(d.conversation, d.token); }
if (d.ok) startPolling();
else bubble(d.error || 'Message could not be sent. Please try again.', false, 'System');
})
.catch(() => bubble('Connection problem — please try again.', false, 'System'));
}
send.addEventListener('click', doSend);
text.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); doSend(); } });
toggle.addEventListener('click', () => {
const opening = !panel.classList.contains('open');
panel.classList.toggle('open', opening);
if (opening) {
if (badge) badge.style.display = 'none';
if (store.conv) { if (lead) lead.style.display = 'none'; startPolling(); }
text.focus();
}
});
widget.querySelector('.chat-ph-x').addEventListener('click', () => panel.classList.remove('open'));
if (store.conv) startPolling();
})();
(function () {
const form = document.getElementById('contactForm');
if (!form) return;
const REQUIRED = ['cf-first', 'cf-last', 'cf-email', 'cf-subject', 'cf-message'];
function val(id) { const el = document.getElementById(id); return el ? el.value.trim() : ''; }
function setErr(id, msg) {
const errEl = document.getElementById(id + '-err');
const input = document.getElementById(id);
if (errEl) errEl.textContent = msg;
if (input) {
input.classList.toggle('is-invalid', !!msg);
input.classList.toggle('is-valid', !msg && input.value.trim() !== '');
}
return !msg;
}
function validateField(id) {
const v = val(id);
if (id === 'cf-email') {
if (!v) return setErr(id, 'Email address is required.');
if (!/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(v)) return setErr(id, 'Please enter a valid email address.');
} else if (id === 'cf-subject') {
if (!v) return setErr(id, 'Please select a subject.');
} else if (id === 'cf-message') {
if (!v) return setErr(id, 'Message is required.');
if (v.length < 20) return setErr(id, 'Please write at least 20 characters.');
} else if (id === 'cf-first') {
if (!v) return setErr(id, 'First name is required.');
} else if (id === 'cf-last') {
if (!v) return setErr(id, 'Last name is required.');
}
return setErr(id, '');
}
REQUIRED.forEach(id => {
const el = document.getElementById(id);
if (!el) return;
el.addEventListener('blur', () => validateField(id));
el.addEventListener('input', () => { if (el.classList.contains('is-invalid')) validateField(id); });
});
form.addEventListener('submit', e => {
e.preventDefault();
const allValid = REQUIRED.map(validateField).every(Boolean);
if (!allValid) {
const first = form.querySelector('.is-invalid');
if (first) first.scrollIntoView({ behavior: 'smooth', block: 'center' });
return;
}
const btn = document.getElementById('cf-submit');
btn.disabled = true;
btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Sending…';
setTimeout(() => {
const success = document.getElementById('cf-success');
if (success) { success.hidden = false; success.scrollIntoView({ behavior: 'smooth', block: 'center' }); }
btn.hidden = true;
REQUIRED.forEach(id => {
const el = document.getElementById(id);
if (el) { el.value = ''; el.classList.remove('is-valid', 'is-invalid'); }
});
}, 1600);
});
})();
(function () {
const form = document.getElementById('newsletterForm');
if (!form) return;
const input = document.getElementById('nl-email');
const errEl = document.getElementById('nl-email-err');
const success = document.getElementById('nl-success');
form.addEventListener('submit', e => {
e.preventDefault();
const v = input ? input.value.trim() : '';
if (!v) { if (errEl) errEl.textContent = 'Please enter your email address.'; return; }
if (!/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(v)) { if (errEl) errEl.textContent = 'Please enter a valid email address.'; return; }
if (errEl) errEl.textContent = '';
const btn = form.querySelector('button[type="submit"]');
if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i>'; }
setTimeout(() => {
if (success) { success.hidden = false; }
form.querySelector('.newsletter-field').style.display = 'none';
if (errEl) errEl.textContent = '';
}, 1200);
});
if (input) input.addEventListener('input', () => { if (errEl) errEl.textContent = ''; });
})();
if ('serviceWorker' in navigator) {
window.addEventListener('load', () => {
navigator.serviceWorker.register('/sw.js').catch(() => {});
});
}
(function () {
if (localStorage.getItem('oh_cookies')) return;
const bar = document.createElement('div');
bar.className = 'cookie-bar';
bar.innerHTML =
'<div class="container">' +
'<div class="cookie-inner">' +
'<p class="cookie-text">We use cookies to improve your experience and analyse site traffic. By clicking “Accept All” you agree to our <a href="#">Cookie Policy</a> and <a href="#">Privacy Policy</a>.</p>' +
'<div class="cookie-btns">' +
'<button type="button" class="btn btn-outline-white btn-sm" id="cookieManage">Manage</button>' +
'<button type="button" class="btn btn-green btn-sm" id="cookieAccept">Accept All</button>' +
'</div>' +
'</div>' +
'</div>';
document.body.appendChild(bar);
setTimeout(() => bar.classList.add('show'), 1400);
function dismiss() {
localStorage.setItem('oh_cookies', '1');
bar.classList.remove('show');
setTimeout(() => bar.remove(), 500);
}
bar.querySelector('#cookieAccept').addEventListener('click', dismiss);
bar.querySelector('#cookieManage').addEventListener('click', dismiss);
})();